SELECT DISTINCT
    rt.id AS roomTypeId,
    rt.name,
    rt.max_occupancy AS maxOccupancy,
    rt.image_url AS imageUrl,
    r.demandrate AS demandRate,
    r.maxrate AS maxRate,
    r.discountrate AS discountRate,
    i.availablecount AS availableCount
FROM room_type rt
JOIN (
    SELECT
        room_type_id,
        MIN(total_inventory - total_reserved) AS availableCount
    FROM room_type_inventory




                date BETWEEN #{startDate} AND #{endDate}

                    AND (total_inventory - total_reserved) >= #{numberOfRooms}



                date = #{today}

                    AND (total_inventory - total_reserved) >= #{numberOfRooms}




    GROUP BY room_type_id


            HAVING COUNT(date) >= #{totalDays}


            HAVING COUNT(date) >= 1


) i ON i.room_type_id = rt.id
JOIN(
    SELECT
        room_type_id,
        SUM(demand_rate) AS demandRate,
        SUM(max_rate) AS maxRate,
        ROUND((SUM(max_rate) - SUM(demand_rate))::numeric / SUM(max_rate) * 100) AS discountRate
    FROM rate



                date BETWEEN #{startDate} AND #{endDate}


                date = #{today}



    GROUP BY room_type_id
) r ON r.room_type_id = rt.id


    rt.hotel_id = #{hotelId}

        AND rt.max_occupancy >= #{numberOfGuests}
